var db *gorm.DB

func DB() *gorm.DB {
	return db
}

func ConnectDB() {
	dsn := os.Getenv("DATABASE_URL")
	if dsn == "" {
		dsn = "host=pg-gvm port=5432 user=pbi password=Pbi12345 dbname=gvmd sslmode=disable"
	}

	// ✅ ปิดการพิมพ์ SQL + ปิดสี
	newLogger := logger.New(
		log.New(os.Stdout, "\r\n", log.LstdFlags),
		logger.Config{
			SlowThreshold:             2 * time.Second,
			LogLevel:                  logger.Silent,
			IgnoreRecordNotFoundError: true,
			Colorful:                  false,
		},
	)

	var database *gorm.DB
	var err error

	maxRetries := 20
	retryDelay := 2 * time.Second

	for i := 1; i <= maxRetries; i++ {
		database, err = gorm.Open(postgres.Open(dsn), &gorm.Config{
			Logger: newLogger,
		})

		if err == nil {
			sqlDB, err2 := database.DB()
			if err2 == nil {
				sqlDB.SetMaxIdleConns(5)
				sqlDB.SetMaxOpenConns(20)
				sqlDB.SetConnMaxLifetime(30 * time.Minute)

				if pingErr := sqlDB.Ping(); pingErr == nil {
					db = database
					fmt.Println("✅ Database connected successfully")
					return
				} else {
					err = pingErr
				}
			} else {
				err = err2
			}
		}

		log.Printf("⏳ DB not ready (attempt %d/%d): %v\n", i, maxRetries, err)
		time.Sleep(retryDelay)
	}

	log.Fatalf("❌ failed to connect to PostgreSQL after %d attempts: %v", maxRetries, err)
}

// ✅ สร้างตารางจาก Entity
func SetupDatabase() {
	if db == nil {
		log.Fatal("❌ database is nil, call ConnectDB() before SetupDatabase()")
	}

	err := db.AutoMigrate(
		&entity.OTP{},
		&entity.AppRole{},
		&entity.AppUser{},
		&entity.SendEmail{},
		&entity.AppLineMaster{},
		&entity.AppNotification{},
		&entity.AppStatusNotify{},
		&entity.AppHistoryNotify{},
		&entity.AppDiagram{},
		&entity.AppDiagramNode{},
		&entity.AppLocation{},
		&entity.AppReport{},
		&entity.AppKEVCache{},
		&entity.AppNVDCache{},
		&entity.AppAssetCriticality{},
		&entity.AppEPSSCache{},
		&entity.AppComplianceMapping{},
		&entity.AppAPIKey{},
		&entity.AppAuditLog{},
	)
	if err != nil {
		log.Fatalf("❌ AutoMigrate failed: %v", err)
	}

	fmt.Println("✅ AutoMigrate completed")
}

// =========================
// Helper: เช็คว่าตารางมีข้อมูลแล้วหรือยัง
// ถ้ามีอย่างน้อย 1 row = true
// =========================
func tableHasAnyRows(model interface{}) bool {
	if db == nil {
		log.Fatal("❌ database is nil, call ConnectDB() before tableHasAnyRows()")
	}

	var count int64
	if err := db.Model(model).Count(&count).Error; err != nil {
		log.Fatalf("❌ failed to count rows for %T: %v", model, err)
	}

	return count > 0
}

// =========================
// Helper: หา Role ตามชื่อ
// =========================
func getRoleByName(roleName string) (*entity.AppRole, error) {
	var role entity.AppRole
	if err := db.Where("role = ?", roleName).First(&role).Error; err != nil {
		return nil, err
	}
	return &role, nil
}

// =========================
// Helper: หา StatusNotify ตามชื่อ
// =========================
func getStatusByName(statusName string) (*entity.AppStatusNotify, error) {
	var status entity.AppStatusNotify
	if err := db.Where("status = ?", statusName).First(&status).Error; err != nil {
		return nil, err
	}
	return &status, nil
}

// =========================
// Helper: หา LineMaster ตัวแรก
// =========================
func getFirstLineMaster() (*entity.AppLineMaster, error) {
	var lineMaster entity.AppLineMaster
	if err := db.First(&lineMaster).Error; err != nil {
		return nil, err
	}
	return &lineMaster, nil
}

// =========================
// Helper: หา AppUser ตัวแรก
// =========================
func getFirstAppUser() (*entity.AppUser, error) {
	var appUser entity.AppUser
	if err := db.Order("id asc").First(&appUser).Error; err != nil {
		return nil, err
	}
	return &appUser, nil
}

